import json,subprocess
s=json.load(open('/tmp/seqs.json'))
out=s['output']; inp=s['input']; egfp=s['egfp']; flag=s['flag']; snap=s['snap']
def rc(x):
    c={'a':'t','t':'a','g':'c','c':'g'}; return ''.join(c[b] for b in reversed(x))
def tm(seq):
    r=subprocess.run(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',seq.upper()],capture_output=True,text=True)
    return float(r.stdout.strip())

# fragment annealing anchors: (name, fwd_template_from_start_func, rev_template_end_func)
# fwd anneal = template[a: a+L]; rev anneal = rc(template[b-L: b])
frags={
 'egfp':(egfp,0,714),
 'flag':(flag,3,87),
 'snap':(snap,3,549),
 'input':(inp,690,210),  # rev end index 210 in inp; fwd start 690
}
# For input rev, template region is inp[210-L:210]; fwd inp[690:690+L]
def anneal_fwd(tmpl,a,L): return tmpl[a:a+L]
def anneal_rev(tmpl,b,L): return rc(tmpl[b-L:b])

results={}
for name,(tmpl,a,b) in frags.items():
    # gather Tm by length
    fwdTm={}; revTm={}
    for L in range(15,37):
        fwdTm[L]=tm(anneal_fwd(tmpl,a,L))
        revTm[L]=tm(anneal_rev(tmpl,b,L))
    # pick pair: both in [58,72], diff<=5, minimize diff then minimize max length
    best=None
    for Lf in range(15,37):
        if not(58<=fwdTm[Lf]<=72): continue
        for Lr in range(15,37):
            if not(58<=revTm[Lr]<=72): continue
            d=abs(fwdTm[Lf]-revTm[Lr])
            if d>5: continue
            score=(round(d,3),Lf+Lr)
            if best is None or score<best[0]:
                best=(score,Lf,Lr,fwdTm[Lf],revTm[Lr])
    results[name]=best
    print(name,'fwd L,Tm rev L,Tm diff:',best[1],round(best[3],2),best[2],round(best[4],2),round(abs(best[3]-best[4]),2))
json.dump({k:(v[1],v[2]) for k,v in results.items()},open('/tmp/lens.json','w'))
PY
