s=json.load(open('/tmp/seqs.json'))
inp=s['input']; egfp=s['egfp']; flag=s['flag']; snap=s['snap']
def rc(x):
    c={'a':'t','t':'a','g':'c','c':'g'}; return ''.join(c[b] for b in reversed(x))
def tm(seq):
    r=subprocess.run(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',seq.upper()],capture_output=True,text=True)
    return float(r.stdout.strip())
frags={'egfp':(egfp,0,714),'flag':(flag,3,87),'snap':(snap,3,549),'input':(inp,690,210)}
def af(t,a,L): return t[a:a+L]
def ar(t,b,L): return rc(t[b-L:b])
res={}
for name,(t,a,b) in frags.items():
    fT={L:tm(af(t,a,L)) for L in range(15,37)}
    rT={L:tm(ar(t,b,L)) for L in range(15,37)}
    best=None
    for Lf in range(15,37):
        if not(58<=fT[Lf]<=72):continue
        for Lr in range(15,37):
            if not(58<=rT[Lr]<=72):continue
            if abs(fT[Lf]-rT[Lr])>5:continue
            score=(round(max(abs(fT[Lf]-65),abs(rT[Lr]-65)),3),round(abs(fT[Lf]-rT[Lr]),3),Lf+Lr)
            if best is None or score<best[0]:
                best=(score,Lf,Lr,fT[Lf],rT[Lr])
    res[name]=(best[1],best[2])
    print(name,'Lf',best[1],round(best[3],2),'Lr',best[2],round(best[4],2),'diff',round(abs(best[3]-best[4]),2))
json.dump(res,open('/tmp/lens.json','w'))
